"use strict";(self.webpackChunkblog=self.webpackChunkblog||[]).push([[1477],{10:function(n){n.exports=JSON.parse('{"blogPosts":[{"id":"set-up-your-umami","metadata":{"permalink":"/blog/set-up-your-umami","editUrl":"https://github.com/zx06/zx06.github.io/edit/main/blog/2022/05-31-umami/index.mdx","source":"@site/blog/2022/05-31-umami/index.mdx","title":"\u4e3a\u4f60\u7684\u535a\u5ba2\u914d\u7f6eanalytics","description":"\u53ef\u4ee5\u53c2\u8003\u6b64\u5904\u4e00\u952e\u90e8\u7f72 running-on-railway","date":"2022-05-31T00:00:00.000Z","formattedDate":"2022\u5e745\u670831\u65e5","tags":[{"label":"docusaurus","permalink":"/blog/tags/docusaurus"},{"label":"analytics","permalink":"/blog/tags/analytics"}],"readingTime":0.34,"hasTruncateMarker":false,"authors":[{"name":"zx06","title":"Maintainer of Blog","url":"https://github.com/zx06","imageURL":"https://github.com/zx06.png","key":"zx06"}],"frontMatter":{"slug":"set-up-your-umami","title":"\u4e3a\u4f60\u7684\u535a\u5ba2\u914d\u7f6eanalytics","authors":["zx06"],"tags":["docusaurus","analytics"]},"nextItem":{"title":"debian\u5b89\u88c5docker","permalink":"/blog/archive-install-docker-on-debian"}},"content":"> \u53ef\u4ee5\u53c2\u8003\u6b64\u5904\u4e00\u952e\u90e8\u7f72 [running-on-railway](https://umami.is/docs/running-on-railway)  \\n> \u4f46\u662f\u6211\u8fd9\u8fb9\u9009\u62e9\u7684\u662f\u4f7f\u7528docker\u955c\u50cf\u5728Railway\u4e0a\u90e8\u7f72  \\n\\n## \u521b\u5efa\u4e00\u4e2agithub\u9879\u76ee\\n\u65b0\u5efa\u4e00\u4e2aDockerfile\\n```dockerfile\\nFROM ghcr.io/mikecao/umami:postgresql-v1.31.0\\nARG PORT\\nARG DATABASE_TYPE postgresql\\nARG DATABASE_URL\\nARG HASH_SALT\\n```\\n## \u53bbrailway\u4e0a\u65b0\u5efa\u4e00\u4e2a\u9879\u76ee\\n*todo*"},{"id":"archive-install-docker-on-debian","metadata":{"permalink":"/blog/archive-install-docker-on-debian","editUrl":"https://github.com/zx06/zx06.github.io/edit/main/blog/2020/03-04-archive-install-docker-on-debian/index.mdx","source":"@site/blog/2020/03-04-archive-install-docker-on-debian/index.mdx","title":"debian\u5b89\u88c5docker","description":"\u652f\u6301\u7684\u7cfb\u7edf\u7248\u672c","date":"2020-03-04T00:00:00.000Z","formattedDate":"2020\u5e743\u67084\u65e5","tags":[{"label":"docker","permalink":"/blog/tags/docker"}],"readingTime":1.39,"hasTruncateMarker":false,"authors":[{"name":"zx06","title":"Maintainer of Blog","url":"https://github.com/zx06","imageURL":"https://github.com/zx06.png","key":"zx06"}],"frontMatter":{"slug":"archive-install-docker-on-debian","title":"debian\u5b89\u88c5docker","authors":["zx06"],"tags":["docker"]},"prevItem":{"title":"\u4e3a\u4f60\u7684\u535a\u5ba2\u914d\u7f6eanalytics","permalink":"/blog/set-up-your-umami"},"nextItem":{"title":"Markdown\u2014\u2014\u5165\u95e8\u6307\u5357","permalink":"/blog/archive-learn-markdown"}},"content":"## \u652f\u6301\u7684\u7cfb\u7edf\u7248\u672c\\n- Buster 10\\n- Stretch 9 (stable) / Raspbian Stretch\\n## \u5220\u9664\u65e7\u7248\u672c\\n```bash\\n$ sudo apt-get remove docker docker-engine docker.io containerd runc\\n```\\n## \u5b89\u88c5Docker Engine\u793e\u533a\u7248\\n### \u8bbe\u7f6eapt\u4ed3\u5e93\\n#### 1. \u66f4\u65b0`apt`\u5305\u7d22\u5f15:\\n```bash\\n$ sudo apt-get update\\n```\\n#### 2. \u5b89\u88c5\u4e00\u4e9b\u5305\u8ba9`apt`\u652f\u6301https:\\n```bash\\n$ sudo apt-get install \\\\\\n    apt-transport-https \\\\\\n    ca-certificates \\\\\\n    curl \\\\\\n    gnupg2 \\\\\\n    software-properties-common\\n```\\n#### 3. \u6dfb\u52a0Docker\u5b98\u65b9GPG key:\\n```bash\\n$ curl -fsSL https://download.docker.com/linux/debian/gpg | sudo apt-key add -\\n$ sudo apt-key fingerprint 0EBFCD88\\n\\npub   4096R/0EBFCD88 2017-02-22\\n      Key fingerprint = 9DC8 5822 9FC7 DD38 854A  E2D8 8D81 803C 0EBF CD88\\nuid                  Docker Release (CE deb) <docker@docker.com>\\nsub   4096R/F273FCD8 2017-02-22\\n```\\n#### 4. \u6dfb\u52a0Docker\u6e90:\\n```bash\\n$ sudo add-apt-repository \\\\\\n   \\"deb [arch=amd64] https://download.docker.com/linux/debian \\\\\\n   $(lsb_release -cs) \\\\\\n   stable\\"\\n```\\n### \u5b89\u88c5Docker\u793e\u533a\u7248\\n#### 1. \u66f4\u65b0`apt`\u5305\u7d22\u5f15:\\n```bash\\n$ sudo apt-get update\\n```\\n#### 2. \u5b89\u88c5:\\n```bash\\n$ sudo apt-get install docker-ce docker-ce-cli containerd.io\\n```\\n## \u5b89\u88c5docker-compose(\u53ef\u9009)\\n#### 1. \u4e0b\u8f7d:\\n```bash\\nsudo curl -L \\"https://github.com/docker/compose/releases/download/1.25.4/docker-compose-$(uname -s)-$(uname -m)\\" -o /usr/local/bin/docker-compose\\n```\\n#### 2. \u589e\u52a0\u53ef\u6267\u884c\u6743\u9650:\\n```bash\\nsudo chmod +x /usr/local/bin/docker-compose\\n\\n```\\n## \u914d\u7f6e\u955c\u50cf\u7ad9\\n> [daocloud](https://www.daocloud.io/mirror) \u63d0\u4f9b\u4e86\u4e00\u4e2a\u4e00\u952e\u914d\u7f6e\u955c\u50cf\u7684\u811a\u672c\\n```bash\\n# \u547d\u4ee4\u884c\u6700\u540e\u9762\u7684\u7f51\u5740\u53ef\u4ee5\u6362\u6210\u522b\u7684\u955c\u50cf\u7ad9\uff0c\u5982\u817e\u8baf: https://mirror.ccs.tencentyun.com\\ncurl -sSL https://get.daocloud.io/daotools/set_mirror.sh | sh -s http://f1361db2.m.daocloud.io\\n```"},{"id":"archive-learn-markdown","metadata":{"permalink":"/blog/archive-learn-markdown","editUrl":"https://github.com/zx06/zx06.github.io/edit/main/blog/2015/10-12-archive-learn-markdown/index.mdx","source":"@site/blog/2015/10-12-archive-learn-markdown/index.mdx","title":"Markdown\u2014\u2014\u5165\u95e8\u6307\u5357","description":"Markdown \u662f\u4e00\u79cd\u8f7b\u91cf\u7ea7\u7684\u300c\u6807\u8bb0\u8bed\u8a00\u300d\uff0c\u5b83\u7684\u4f18\u70b9\u5f88\u591a\uff0c\u76ee\u524d\u4e5f\u88ab\u8d8a\u6765\u8d8a\u591a\u7684\u5199\u4f5c\u7231\u597d\u8005\uff0c\u64b0\u7a3f\u8005\u5e7f\u6cdb\u4f7f\u7528\u3002","date":"2015-10-12T00:00:00.000Z","formattedDate":"2015\u5e7410\u670812\u65e5","tags":[{"label":"web","permalink":"/blog/tags/web"},{"label":"markdown","permalink":"/blog/tags/markdown"}],"readingTime":3.3,"hasTruncateMarker":false,"authors":[{"name":"zx06","title":"Maintainer of Blog","url":"https://github.com/zx06","imageURL":"https://github.com/zx06.png","key":"zx06"}],"frontMatter":{"slug":"archive-learn-markdown","title":"Markdown\u2014\u2014\u5165\u95e8\u6307\u5357","authors":["zx06"],"tags":["web","markdown"]},"prevItem":{"title":"debian\u5b89\u88c5docker","permalink":"/blog/archive-install-docker-on-debian"},"nextItem":{"title":"\u4fee\u6539rc.local\u6587\u4ef6\uff0c\u8bbe\u7f6e\u5f00\u673a\u542f\u52a8","permalink":"/blog/archive-autorun"}},"content":"> **Markdown \u662f\u4e00\u79cd\u8f7b\u91cf\u7ea7\u7684\u300c\u6807\u8bb0\u8bed\u8a00\u300d\uff0c\u5b83\u7684\u4f18\u70b9\u5f88\u591a\uff0c\u76ee\u524d\u4e5f\u88ab\u8d8a\u6765\u8d8a\u591a\u7684\u5199\u4f5c\u7231\u597d\u8005\uff0c\u64b0\u7a3f\u8005\u5e7f\u6cdb\u4f7f\u7528\u3002**\\n\\n## Markdown\u7684\u4e00\u4e9b\u7b80\u8981\u89c4\u5219\\n### \u6807\u9898\\n\u5728 Markdown \u4e2d\uff0c\u5982\u679c\u4e00\u6bb5\u6587\u5b57\u88ab\u5b9a\u4e49\u4e3a\u6807\u9898\uff0c\u53ea\u8981\u5728\u8fd9\u6bb5\u6587\u5b57\u524d\u52a0 # \u53f7\u5373\u53ef\u3002\\n\\n```# \u4e00\u7ea7\u6807\u9898\\n## \u4e8c\u7ea7\u6807\u9898\\n### \u4e09\u7ea7\u6807\u9898\\n###### \u516d\u7ea7\u6807\u9898\\n```\\n\u5728\u884c\u9996\u63d2\u5165 1 \u5230 6 \u4e2a # \uff0c\u5bf9\u5e94\u5230\u6807\u9898 1 \u5230 6 \u9636\\n\\n![](./markdownhead.jpg)\\n* ### \u5217\u8868\\nMarkdown \u652f\u6301\u6709\u5e8f\u5217\u8868\u548c\u65e0\u5e8f\u5217\u8868\u3002\\n\u65e0\u5e8f\u5217\u8868\u4f7f\u7528\u661f\u53f7\u3001\u52a0\u53f7\u6216\u662f\u51cf\u53f7\u4f5c\u4e3a\u5217\u8868\u6807\u8bb0\uff1a\\n```\\n* a\\n+ b\\n- c\\n```\\n\u663e\u793a\u7684\u7ed3\u679c\u90fd\u662f\u4e00\u6837\uff1a\\n\\n![](./markdownlist1.jpg)\\n\\n\u6709\u5e8f\u5217\u8868\u5219\u4f7f\u7528\u6570\u5b57\u63a5\u7740\u4e00\u4e2a\u82f1\u6587\u53e5\u70b9\uff1a\\n```\\n1. a\\n2. b\\n3. c\\n```\\n\u4f46\u662f\u6570\u5b57\u7684\u987a\u5e8f\u5374\u5e76\u4e0d\u5f71\u54cd\u751f\u6210\u7684\u6709\u5e8f\u5217\u8868\u7ed3\u679c\\n\u50cf\uff1a\\n```\\n1. a\\n1. b\\n1. c\\n```\\n\u6216\u8005\uff1a\\n```\\n3. a\\n8. b\\n4. c\\n```\\n\u6700\u540e\u751f\u6210\u7684\u7ed3\u679c\u90fd\u662f\\n\\n![](./markdownlist.jpg)\\n\\n\u6240\u4ee5\u5f53\u4f60\u9700\u8981\u5728\u884c\u9996\u8f93\u5165\u7c7b\u4f3c**3.14**\u8fd9\u6837\u7684\u5e26.\u6570\u5b57\u65f6\u9700\u8981\u5728.\u524d\u9762\u52a0\u4e0a\'\\\\\'\u5c31\u50cf**3\\\\\\\\.14**\\n### \u5f15\u7528\\n\u5982\u679c\u4f60\u9700\u8981\u5f15\u7528\u4e00\u5c0f\u6bb5\u522b\u5904\u7684\u53e5\u5b50\uff0c\u90a3\u4e48\u5c31\u8981\u7528\u5f15\u7528\u7684\u683c\u5f0f\u3002\\n\u5728\u53e5\u5b50\u524d\u9762\u52a0\u4e0a\u5927\u4e8e\u53f7\u4f8b\u5982\uff1a\\n**\\\\> \u8fd9\u662f\u5f15\u7528**\\n\u663e\u793a\u6548\u679c\uff1a\\n> \u8fd9\u662f\u5f15\u7528\\n\\n### \u56fe\u7247\u4e0e\u94fe\u63a5\\n\u94fe\u63a5\u7684\u683c\u5f0f\u662f\u8fd9\u6837\uff1a \\\\[\u94fe\u63a5\u663e\u793a\u7684\u6587\u5b57](\u94fe\u63a5\u5730\u5740)\\n\u56fe\u7247\u7684\u533a\u522b\u5728\u4e8e\u524d\u9762\u591a\u4e86\u4e00\u4e2a\'!\'\\n\\n![](./markdownurlimg.jpg)\\n### \u7c97\u4f53\u548c\u659c\u4f53\\nMarkdown \u7684\u7c97\u4f53\u548c\u659c\u4f53\u4e5f\u975e\u5e38\u7b80\u5355\uff0c\u7528\\\\*\\\\*\u5305\u542b\u4e00\u6bb5\u6587\u672c\u5c31\u662f\u7c97\u4f53\u7684\u8bed\u6cd5\uff0c\u7528\\\\*\u5305\u542b\u4e00\u6bb5\u6587\u672c\u5c31\u662f\u659c\u4f53\u7684\u8bed\u6cd5\u3002\\n\\n\\\\*\\\\***\u7c97\u4f53**\\\\*\\\\* \\n\\n\\\\**\u659c\u4f53*\\\\*\\n### \u8868\u683c\\n```\\n\\t| ABCD | EFGH | IJKL |\\n\\t|------|:----:|-----:|\\n\\t| a    | b    | c    |\\n\\t| d    | e    |  f   |\\n\\t| g    | h    |   i  |\\n```\\n\u4e0a\u9762\u7684\u683c\u5f0f\u5c31\u80fd\u751f\u6210\u4ee5\u4e0b\u8868\u683c  \\n\u5176\u4e2d\':\'\u662f\u6807\u8bb0\u5bf9\u5176\u65b9\u5f0f\uff0c\u653e\u540e\u9762\u5c31\u662f\u53f3\u5bf9\u9f50\u4e24\u8fb9\u90fd\u6709\u5c31\u662f\u5c45\u4e2d\u4e86\uff0c\u5f53\u7136\u653e\u524d\u9762\u5c31\u662f\u9ed8\u8ba4\u7684\u683c\u5f0f\u5de6\u5bf9\u9f50\u4e86\u3002  \\n \\n![](./markdownsheet.jpg)\\n\\n\u4e0d\u540c\u7684\u8f6f\u4ef6\u8868\u683c\u663e\u793a\u7684\u6548\u679c\u4e5f\u4e0d\u4e00\u6837\\n\u8868\u683c\u5e94\u8be5\u662fmarkdown\u4e2d\u6700\u5751\u7684\u5730\u65b9\u4e86\uff0c\u53cd\u6b63markdown\u53ef\u4ee5\u5d4c\u53bbhtml\u8bed\u53e5\uff0c\u5b8c\u5168\u53ef\u4ee5\u7528\u5b83\u6765\u753b\u3002\\n\\n\\t\\n### \u4ee3\u7801\\n\u5982\u679c\u4f60\u53ea\u60f3\u9ad8\u4eae\u8bed\u53e5\u4e2d\u7684\u67d0\u4e2a\u51fd\u6570\u540d\u6216\u5173\u952e\u5b57\uff0c\u53ef\u4ee5\u4f7f\u7528 `function_name()` \u5b9e\u73b0\u901a\u5e38\u7f16\u8f91\u5668\u6839\u636e\u4ee3\u7801\u7247\u6bb5\u9002\u914d\u5408\u9002\u7684\u9ad8\u4eae\u65b9\u6cd5\uff0c\u4f46\u4f60\u4e5f\u53ef\u4ee5\u7528 \\\\`\\\\`\\\\` \u5305\u88f9\u4e00\u6bb5\u4ee3\u7801\uff0c\u5e76\u6307\u5b9a\u4e00\u79cd\u8bed\u8a00\\n```java\\npublic class Hello{\\n\\tpublic static void mian(String [] args){\\n\\t\\tSystem.out.printls(\\"Hello World!\\");\\n\\t}\\n}\\n```\\n> \u6ce8\u610f\\\\`\u662f\u6570\u5b571\u5de6\u8fb9\u90a3\u4e2a\u952e\\n\\n### \u5206\u5272\u7ebf\\n\u8fde\u7eed\u4e09\u4e2a\u4ee5\u4e0a`*`\u6216`-`\\n\\nline1\\n\\n******\\n\\nline2\\n\\n### \u53c2\u8003\u6587\u6863\\n- [Markdown \u5b98\u65b9\u6559\u7a0b](https://markdown.com.cn/)"},{"id":"archive-autorun","metadata":{"permalink":"/blog/archive-autorun","editUrl":"https://github.com/zx06/zx06.github.io/edit/main/blog/2015/10-11-archive-autorun/index.mdx","source":"@site/blog/2015/10-11-archive-autorun/index.mdx","title":"\u4fee\u6539rc.local\u6587\u4ef6\uff0c\u8bbe\u7f6e\u5f00\u673a\u542f\u52a8","description":"\u4e3a\u4e86\u5728\u6811\u8393\u6d3e\u542f\u52a8\u7684\u65f6\u5019\u8fd0\u884c\u4e00\u4e2a\u547d\u4ee4\u6216\u7a0b\u5e8f\uff0c\u4f60\u9700\u8981\u5c06\u547d\u4ee4\u6dfb\u52a0\u5230rc.local\u6587\u4ef6\u4e2d\u3002\u8fd9\u5bf9\u4e8e\u60f3\u8981\u5728\u6811\u8393\u6d3e\u63a5\u901a\u7535\u6e90\u540e\u65e0\u9700\u914d\u7f6e\u76f4\u63a5\u8fd0\u884c\u7a0b\u5e8f\uff0c\u6216\u8005\u4e0d\u5e0c\u671b\u6bcf\u6b21\u90fd\u624b\u52a8\u542f\u52a8\u7a0b\u5e8f\u7684\u60c5\u51b5\u975e\u5e38\u6709\u7528\u3002","date":"2015-10-11T00:00:00.000Z","formattedDate":"2015\u5e7410\u670811\u65e5","tags":[{"label":"linux","permalink":"/blog/tags/linux"},{"label":"\u6811\u8393\u6d3e","permalink":"/blog/tags/\u6811\u8393\u6d3e"}],"readingTime":1.255,"hasTruncateMarker":false,"authors":[{"name":"zx06","title":"Maintainer of Blog","url":"https://github.com/zx06","imageURL":"https://github.com/zx06.png","key":"zx06"}],"frontMatter":{"slug":"archive-autorun","title":"\u4fee\u6539rc.local\u6587\u4ef6\uff0c\u8bbe\u7f6e\u5f00\u673a\u542f\u52a8","authors":["zx06"],"tags":["linux","\u6811\u8393\u6d3e"]},"prevItem":{"title":"Markdown\u2014\u2014\u5165\u95e8\u6307\u5357","permalink":"/blog/archive-learn-markdown"},"nextItem":{"title":"\u6811\u8393\u6d3e\u5b89\u88c5samba","permalink":"/blog/archive-install-samba"}},"content":"> \u4e3a\u4e86\u5728\u6811\u8393\u6d3e\u542f\u52a8\u7684\u65f6\u5019\u8fd0\u884c\u4e00\u4e2a\u547d\u4ee4\u6216\u7a0b\u5e8f\uff0c\u4f60\u9700\u8981\u5c06\u547d\u4ee4\u6dfb\u52a0\u5230rc.local\u6587\u4ef6\u4e2d\u3002\u8fd9\u5bf9\u4e8e\u60f3\u8981\u5728\u6811\u8393\u6d3e\u63a5\u901a\u7535\u6e90\u540e\u65e0\u9700\u914d\u7f6e\u76f4\u63a5\u8fd0\u884c\u7a0b\u5e8f\uff0c\u6216\u8005\u4e0d\u5e0c\u671b\u6bcf\u6b21\u90fd\u624b\u52a8\u542f\u52a8\u7a0b\u5e8f\u7684\u60c5\u51b5\u975e\u5e38\u6709\u7528\u3002\\n\\n* ## \u7f16\u8f91rc.local\u6587\u4ef6\\n\\n``` bash\\npi@raspberrypi / $ sudo nano /etc/rc.local\\n```\\n``` bash\\n#!/bin/sh -e\\n#\\n# rc.local\\n#\\n# This script is executed at the end of each multiuser runlevel.\\n# Make sure that the script will \\"exit 0\\" on success or any other\\n# value on error.\\n#\\n# In order to enable or disable this script just change the execution\\n# bits.\\n#\\n# By default this script does nothing.\\n\\n# Print the IP address\\n_IP=$(hostname -I) || true\\nif [ \\"$_IP\\" ]; then\\n  printf \\"My IP address is %s\\\\n\\" \\"$_IP\\"\\nfi\\n\\nexit 0\\n\\n```\\n\u5728eixt 0 \u524d\u9762\u52a0\u5165\u8981\u6267\u884c\u7684\u547d\u4ee4 **\'/bin/oraynewph status &\'** #\u5982\u679c\u4f60\u7684\u547d\u4ee4\u9700\u8981\u957f\u65f6\u95f4\u8fd0\u884c\uff08\u4f8b\u5982\u6b7b\u5faa\u73af\uff09\u6216\u8005\u8fd0\u884c\u540e\u4e0d\u80fd\u9000\u51fa\uff0c\u90a3\u4e48\u4f60\u5fc5\u987b\u786e\u4fdd\u5728\u547d\u4ee4\u7684\u6700\u540e\u6dfb\u52a0\u201c&\u201d\u7b26\u53f7\u8ba9\u547d\u4ee4\u8fd0\u884c\u5728\u5176\u5b83\u8fdb\u7a0b"},{"id":"archive-install-samba","metadata":{"permalink":"/blog/archive-install-samba","editUrl":"https://github.com/zx06/zx06.github.io/edit/main/blog/2015/10-10-archive-install-samba/inxe.mdx","source":"@site/blog/2015/10-10-archive-install-samba/inxe.mdx","title":"\u6811\u8393\u6d3e\u5b89\u88c5samba","description":"\u901a\u8fc7\u4f7f\u7528samba\u670d\u52a1\uff0c\u53ef\u4ee5\u81ea\u7531\u8bbf\u95ee\u4fee\u6539\u6811\u8393\u6d3ehome\u76ee\u5f55\u4e0b\u7684\u6587\u4ef6","date":"2015-10-10T00:00:00.000Z","formattedDate":"2015\u5e7410\u670810\u65e5","tags":[{"label":"smaba","permalink":"/blog/tags/smaba"},{"label":"\u6811\u8393\u6d3e","permalink":"/blog/tags/\u6811\u8393\u6d3e"}],"readingTime":0.995,"hasTruncateMarker":false,"authors":[{"name":"zx06","title":"Maintainer of Blog","url":"https://github.com/zx06","imageURL":"https://github.com/zx06.png","key":"zx06"}],"frontMatter":{"slug":"archive-install-samba","title":"\u6811\u8393\u6d3e\u5b89\u88c5samba","authors":["zx06"],"tags":["smaba","\u6811\u8393\u6d3e"]},"prevItem":{"title":"\u4fee\u6539rc.local\u6587\u4ef6\uff0c\u8bbe\u7f6e\u5f00\u673a\u542f\u52a8","permalink":"/blog/archive-autorun"}},"content":"\u901a\u8fc7\u4f7f\u7528samba\u670d\u52a1\uff0c\u53ef\u4ee5\u81ea\u7531\u8bbf\u95ee\u4fee\u6539\u6811\u8393\u6d3ehome\u76ee\u5f55\u4e0b\u7684\u6587\u4ef6\\n* ## \u5b89\u88c5 smaba:\\n``` bash\\nsudo apt-get install samba samba-common-bin\\n```\\n* ## \u4fee\u6539\u914d\u7f6e\u6587\u4ef6\\n``` bash\\nsudo nano /etc/samba/smb.conf\\n```\\n\u4e0b\u9762\u7684\u914d\u7f6e\u662f\u8ba9\u7528\u6237\u53ef\u4ee5\u8bbf\u95ee\u81ea\u5df1\u7684 home \u76ee\u5f55\\n1. \u5f00\u542f\u7528\u6237\u8ba4\u8bc1\uff0c\u627e\u5230\u201c##### Authentication #####\u201d\uff0c\u6dfb\u52a0\u201csecurity = user\u201d\\n2. \u914d\u7f6e\u7528\u6237\u53ef\u4ee5\u8bfb\u5199\u81ea\u5df1\u7684 home \u76ee\u5f55\uff0c\u5728\u201c[homes]\u201d\u8282\u4e2d\uff0c\u628a \u201cread only = yes\u201d \u6539\u4e3a \u201cread only = no\u201d\\n3. \u627e\u5230browseable=no\u6539\u4e3ayes \u5426\u5219\u7b49\u4f1a\u8bbf\u95ee\u65f6\u6b64\u6587\u4ef6\u5939\u4f1a\u9690\u85cf\\n* ## \u91cd\u542fsamba\u670d\u52a1\\n``` bash\\nsudo /etc/init.d/samba restart\\n```\\n* ## \u628a\u7cfb\u7edf\u9ed8\u8ba4\u7528\u6237pi\u6dfb\u52a0\u5230samba\\n``` bash\\nsudo smbpasswd -a pi\\n```\\n\u6839\u636e\u63d0\u793a\u8f93\u5165\u5bc6\u7801\\n* ## windows\u8bbf\u95ee\\n\u6253\u5f00\u6587\u4ef6\u8d44\u6e90\u7ba1\u7406\u5668\uff0c\u8f93\u5165\\\\\\\\192.168.1.104\\\\pi\\n![\u6587\u4ef6\u8d44\u6e90\u7ba1\u7406\u5668](./samba.jpg)"}]}')}}]);